Hi @tjferry14!

The call to initialize tablesorter needs to be inside the sheetrock callback ([demo](https://jsfiddle.net/Mottie/auoqwp8p/6/)):

```js
$('#audio-backend').sheetrock({
  url: mySpreadsheet,
  query: sql,
  rowTemplate: bandsTemplate,
  callback: function(error, options, response) {
    if (!error) {
      if ($('#audio-backend tr').length == 1) {
        $('#audio-backend').append("<h3>No results.</h3>")
      }
    } else {
      $('#audio-backend').append('<h3>Error.</h3>');
    }
    $("#audio-backend").tablesorter();
  }
});
```

